+    local procedure NormalizeContractEntryNoFilter(var Filter: Text)
+    var
+        NormalizedFilter: Text;
+        CurrentEntry: Text;
+        RemainingFilter: Text;
+        EntrySeparatorPos: Integer;
+        RangeSeparatorPos: Integer;
+        FromValue: Integer;
+        ToValue: Integer;
+    begin
+        if Filter = '' then
+            exit;
+
+        RemainingFilter := Filter;
+        repeat
+            EntrySeparatorPos := StrPos(RemainingFilter, '|');
+            if EntrySeparatorPos = 0 then begin
+                CurrentEntry := RemainingFilter;
+                RemainingFilter := '';
+            end else begin
+                CurrentEntry := CopyStr(RemainingFilter, 1, EntrySeparatorPos - 1);
+                RemainingFilter := CopyStr(RemainingFilter, EntrySeparatorPos + 1);
+            end;
+
+            RangeSeparatorPos := StrPos(CurrentEntry, '..');
+            if RangeSeparatorPos <> 0 then
+                if Evaluate(FromValue, CopyStr(CurrentEntry, 1, RangeSeparatorPos - 1)) and Evaluate(ToValue, CopyStr(CurrentEntry, RangeSeparatorPos + 2)) then
+                    if FromValue > ToValue then
+                        CurrentEntry := Format('%1..%2', ToValue, FromValue);
+
+            if CurrentEntry <> '' then begin
+                if NormalizedFilter <> '' then
+                    NormalizedFilter += '|';
+                NormalizedFilter += CurrentEntry;
+            end;
+        until RemainingFilter = '';
+
+        Filter := NormalizedFilter;
+    end;
